import { Test, TestingModule } from '@nestjs/testing';
import { AuthService } from './../../auth.service';
import { PrismaService } from './../../../../libs/database/prisma';
import { JwtService } from '@nestjs/jwt';
import { MailerService } from '@nestjs-modules/mailer';
import { UsersService } from './../../../users/users.service';
import {
  ForgotPasswordService,
  RefreshTokenService,
  RegisterUserService,
  SignInService,
  SignOutService,
} from './../../services';
import { CryptoService } from './../../../../libs/crypto/services/crypto.service';
import { PasswordService } from './../../../../libs/crypto/services/password.service';
import { JwtHandlerService } from './../../../../libs/crypto/services/jwt.service';
import { SignInVerifyService } from './../../services/signInVerify.service';
import { EmailService } from './../../../../libs/services/mailer/mail.service';
import { ConfigService } from '@nestjs/config';
import { CreateUserDTO } from './../../../../libs';
import { BadRequestException, UnauthorizedException } from '@nestjs/common';
import * as bcrypt from 'bcrypt';
import { Role, User } from '@prisma/client';
import { UsersModule } from './../../../../modules/users/users.module';

describe('AuthService (integration)', () => {
  let authService: AuthService;
  let prisma: PrismaService;
  let passwordService: PasswordService;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      imports: [
        // ADICIONE ESTES MÓDULOS/SERVIÇOS:
        UsersModule, // Ou importe os serviços individualmente
      ],
      providers: [
        AuthService,
        RegisterUserService,
        SignInService,
        SignInVerifyService,
        SignOutService,
        ForgotPasswordService,
        RefreshTokenService,
        UsersService,
        CryptoService,
        PasswordService,
        JwtHandlerService,
        EmailService,
        ConfigService,
        {
          provide: PrismaService,
          useValue: {
            user: {
              findUnique: jest.fn(),
              create: jest.fn(),
              update: jest.fn(),
            },
            refreshToken: {
              create: jest.fn(),
              deleteMany: jest.fn(),
              findFirst: jest.fn(),
            },
          },
        },
        {
          provide: JwtService,
          useValue: {
            sign: jest.fn().mockReturnValue('mocked-jwt-token'),
            verify: jest
              .fn()
              .mockReturnValue({ sub: '1', email: 'test@test.com' }),
          },
        },
        {
          provide: MailerService,
          useValue: {
            sendMail: jest.fn().mockResolvedValue(true),
          },
        },
      ],
    }).compile();

    authService = module.get<AuthService>(AuthService);
    prisma = module.get<PrismaService>(PrismaService);
    passwordService = module.get<PasswordService>(PasswordService);
  });

  it('deve estar definido', () => {
    expect(authService).toBeDefined();
  });

  describe('register', () => {
    it('deve criar usuário com todos os campos e senha hasheada', async () => {
      // Arrange
      const dto: CreateUserDTO = {
        firstname: 'John',
        lastname: 'Doe',
        nickname: 'johndoe',
        email: 'test@test.com',
        password: '123456',
        role: Role.USER,
      };

      const mockUser: {
        id: number;
        firstname: string;
        lastname: string;
        nickname: string;
        email: string;
        password: string;
        role: Role;
        clientData: null;
        refreshToken: string | null;
        emailVerifiedAt: Date | null;
        createdAt: Date;
        updatedAt: Date;
      } = {
        id: 1,
        firstname: dto.firstname,
        lastname: dto.lastname,
        nickname: dto.nickname,
        email: dto.email,
        password: 'hashed_123456',
        role: Role.USER,
        clientData: null,
        refreshToken: null,
        emailVerifiedAt: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      jest.spyOn(prisma.user, 'findUnique').mockResolvedValue(null);
      jest.spyOn(prisma.user, 'create').mockResolvedValue(mockUser);
      (
        jest.spyOn(passwordService, 'hash') as jest.MockedFunction<
          PasswordService['hash']
        >
      ).mockResolvedValue('hashed_123456');

      // Act
      const result = await authService.register(dto);

      // Assert
      const findUniqueSpy = jest.spyOn(prisma.user, 'findUnique');

      expect(findUniqueSpy).toHaveBeenCalledWith({
        where: { email: dto.email },
      });

      const createSpy = jest.spyOn(prisma.user, 'create');

      expect(createSpy).toHaveBeenCalledWith({
        data: expect.objectContaining({
          firstname: 'John',
          lastname: 'Doe',
          nickname: 'johndoe',
          email: 'test@test.com',
          password: 'hashed_123456',
          role: 'USER',
        }) as unknown as User,
      });

      expect(result).toEqual(
        expect.objectContaining({
          id: 1,
          firstname: 'John',
          lastname: 'Doe',
          nickname: 'johndoe',
          email: 'test@test.com',
          role: 'USER',
        }),
      );
    });

    it('deve falhar ao tentar registrar email duplicado', async () => {
      // Arrange
      const dto: CreateUserDTO = {
        firstname: 'John',
        lastname: 'Doe',
        nickname: 'johndoe',
        email: 'duplicate@test.com',
        password: '123456',
        role: 'USER',
      };

      const existingUser: User = {
        id: 1,
        firstname: dto.firstname,
        lastname: dto.lastname,
        nickname: dto.nickname,
        email: dto.email,
        password: 'hashed_123456',
        role: Role.USER, // enum do Prisma
        refreshToken: null,
        emailVerifiedAt: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      jest.spyOn(prisma.user, 'findUnique').mockResolvedValue(existingUser);

      // Act & Assert
      await expect(authService.register(dto)).rejects.toThrow(
        BadRequestException,
      );
    });
  });

  describe('signIn', () => {
    it('deve fazer login com credenciais válidas', async () => {
      // Arrange
      const email = 'valid@test.com';
      const password = '123456';

      const user = {
        id: 1,
        firstname: 'John',
        lastname: 'Doe',
        nickname: 'johndoe',
        email: email,
        password: await bcrypt.hash(password, 10), // Senha hasheada
        role: Role.USER,
        emailVerifiedAt: null,
        refreshToken: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      const updatedUser = {
        ...user,
        refreshToken: 'refresh-token', // Usuário atualizado com o refresh token
        updatedAt: new Date(),
      };

      // Mock para encontrar o usuário
      jest.spyOn(prisma.user, 'findUnique').mockResolvedValue(user);

      // Mock para atualizar o usuário com o refresh token
      jest.spyOn(prisma.user, 'update').mockResolvedValue(updatedUser);

      // Act
      const result = await authService.signIn(email, password);

      // Assert
      expect(result).toEqual({
        accessToken: 'mocked-jwt-token',
        refreshToken: 'refresh-token',
        user: expect.objectContaining({
          id: 1,
          email: 'valid@test.com',
          firstname: 'John',
          lastname: 'Doe',
        }) as unknown as User,
      });
    });
  });

  it('deve falhar ao fazer login com senha inválida', async () => {
    // Arrange
    const email = 'valid@test.com';
    const user = {
      id: 1,
      firstname: 'John',
      lastname: 'Doe',
      nickname: 'johndoe',
      email: email,
      password: await bcrypt.hash('correct_password', 10),
      role: Role.USER,
      emailVerifiedAt: null,
      refreshToken: null,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    jest.spyOn(prisma.user, 'findUnique').mockResolvedValue(user);

    // Act & Assert
    await expect(authService.signIn(email, 'wrong_password')).rejects.toThrow(
      UnauthorizedException,
    );
  });

  describe('refreshToken', () => {
    it('deve renovar token com refresh token válido', async () => {
      // Arrange
      const validRefreshToken = 'valid-refresh-token';

      const user = {
        id: 1,
        firstname: 'John',
        lastname: 'Doe',
        nickname: 'johndoe',
        email: 'test@test.com',
        password: 'hashed',
        role: Role.USER,
        emailVerifiedAt: null,
        refreshToken: validRefreshToken, // O refresh token está armazenado aqui
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      const updatedUser = {
        ...user,
        refreshToken: 'new-refresh-token', // Usuário com novo refresh token
      };

      // Mock para encontrar o usuário pelo refresh token
      const mockFindUser = jest.spyOn(prisma.user, 'findFirst');
      mockFindUser.mockResolvedValue(user);

      // Mock para atualizar o usuário com o novo refresh token
      const mockUpdateUser = jest.spyOn(prisma.user, 'update');
      mockUpdateUser.mockResolvedValue(updatedUser);

      // Act
      const result = await authService.refreshToken(validRefreshToken);

      // Assert
      expect(result).toEqual({
        accessToken: 'mocked-jwt-token',
        refreshToken: 'new-refresh-token',
      });

      // Verificar se os mocks foram chamados corretamente
      expect(mockFindUser).toHaveBeenCalledWith({
        where: { refreshToken: validRefreshToken },
      });

      expect(mockUpdateUser).toHaveBeenCalledWith({
        where: { id: 1 },
        data: { refreshToken: 'new-refresh-token' },
      });
    });
  });
});
